from flask import Flask, request, jsonify
import redis
import re

app = Flask(__name__)

# Connect to Redis
redis_client = redis.Redis(host='localhost', port=6379, decode_responses=True)

# Whitelist of allowed Redis commands for cache management
ALLOWED_COMMANDS = {
    'GET', 'SET', 'DEL', 'EXISTS', 'EXPIRE', 'TTL', 'KEYS',
    'FLUSHDB', 'DBSIZE', 'INFO', 'PING', 'MGET', 'MSET',
    'INCR', 'DECR', 'HGET', 'HSET', 'HDEL', 'HGETALL',
    'LPUSH', 'RPUSH', 'LPOP', 'RPOP', 'LRANGE', 'LLEN',
    'SADD', 'SREM', 'SMEMBERS', 'SISMEMBER',
    'ZADD', 'ZREM', 'ZRANGE', 'ZCARD'
}

# Dangerous commands that should never be allowed
DANGEROUS_COMMANDS = {
    'FLUSHALL', 'CONFIG', 'SHUTDOWN', 'BGREWRITEAOF', 'BGSAVE',
    'SAVE', 'DEBUG', 'SLAVEOF', 'REPLICAOF', 'SYNC', 'PSYNC',
    'SCRIPT', 'EVAL', 'EVALSHA', 'MODULE', 'ACL', 'MIGRATE',
    'RESTORE', 'CLUSTER', 'READONLY', 'READWRITE'
}

def validate_redis_command(command_string):
    """
    Validate and sanitize Redis command input.
    Returns tuple: (is_valid, error_message, parsed_command)
    """
    if not command_string or not isinstance(command_string, str):
        return False, "Command must be a non-empty string", None
    
    # Remove extra whitespace and split command
    parts = command_string.strip().split()
    
    if not parts:
        return False, "Empty command", None
    
    command_name = parts[0].upper()
    
    # Check if command is in dangerous list
    if command_name in DANGEROUS_COMMANDS:
        return False, f"Command '{command_name}' is not allowed for security reasons", None
    
    # Check if command is in whitelist
    if command_name not in ALLOWED_COMMANDS:
        return False, f"Command '{command_name}' is not in the allowed list", None
    
    # Additional validation for specific commands
    if command_name == 'KEYS' and len(parts) > 1:
        # Restrict KEYS pattern to prevent performance issues
        pattern = parts[1]
        if pattern == '*' or pattern.count('*') > 2:
            return False, "KEYS pattern too broad - use more specific patterns", None
    
    if command_name == 'FLUSHDB':
        # Require explicit confirmation for FLUSHDB
        if len(parts) < 2 or parts[1].upper() != 'ASYNC':
            return False, "FLUSHDB requires ASYNC parameter for safety", None
    
    return True, None, parts

@app.route('/admin/redis', methods=['POST'])
def execute_redis_command():
    """
    Execute Redis commands with strict validation and whitelisting.
    """
    try:
        # Get command from request
        command = request.args.get('command') or request.json.get('command') if request.is_json else None
        
        if not command:
            return jsonify({
                'success': False,
                'error': 'No command provided. Use ?command=<redis_command> or JSON body'
            }), 400
        
        # Validate command
        is_valid, error_message, parsed_command = validate_redis_command(command)
        
        if not is_valid:
            return jsonify({
                'success': False,
                'error': error_message
            }), 403
        
        # Execute validated command
        result = redis_client.execute_command(*parsed_command)
        
        return jsonify({
            'success': True,
            'command': command,
            'result': result
        }), 200
        
    except redis.exceptions.ResponseError as e:
        return jsonify({
            'success': False,
            'error': f'Redis error: {str(e)}'
        }), 400
    except redis.exceptions.ConnectionError as e:
        return jsonify({
            'success': False,
            'error': 'Failed to connect to Redis'
        }), 500
    except Exception as e:
        return jsonify({
            'success': False,
            'error': f'Unexpected error: {str(e)}'
        }), 500

@app.route('/admin/redis/allowed-commands', methods=['GET'])
def get_allowed_commands():
    """
    Return list of allowed Redis commands.
    """
    return jsonify({
        'allowed_commands': sorted(list(ALLOWED_COMMANDS)),
        'note': 'Only these commands can be executed via the API'
    }), 200

@app.route('/health', methods=['GET'])
def health_check():
    """
    Health check endpoint.
    """
    try:
        redis_client.ping()
        return jsonify({'status': 'healthy', 'redis': 'connected'}), 200
    except:
        return jsonify({'status': 'unhealthy', 'redis': 'disconnected'}), 503

if __name__ == '__main__':
    app.run(debug=False, host='127.0.0.1', port=5000)